import { queryCell } from "@1771technologies/lytenyte-shared";
import { useEvent } from "../../../../hooks/use-event.js";
import { runWithBackoff } from "@1771technologies/js-utils";
import { getTabbables } from "@1771technologies/dom-utils";
export function useEditBegin(props, api, view, edit, vp, gridId) {
    return useEvent(({ init, column: c, rowIndex, focusIfNotEditable }) => {
        const row = api.rowByIndex(rowIndex).get();
        const column = typeof c === "number"
            ? api.columnByIndex(c)
            : typeof c === "string"
                ? api.columnById(c)
                : api.columnById(c.id);
        const columnIndex = view.visibleColumns.findIndex((x) => x.id === column?.id);
        if (!vp || !row || !column || columnIndex == -1 || props.rowFullWidthPredicate?.({ rowIndex, row, api }))
            return;
        // If there is already an active edit commit it.
        edit.commit();
        const base = props.columnBase;
        const editable = column.editable ?? base?.editable ?? false;
        if (typeof editable === "function"
            ? !editable({ api, row, column, rowIndex, colIndex: columnIndex })
            : !editable) {
            if (focusIfNotEditable) {
                api.scrollIntoView({ column, row: rowIndex, behavior: "instant" });
                runWithBackoff(() => {
                    const cell = queryCell(gridId, rowIndex, columnIndex, vp);
                    if (!cell)
                        return false;
                    cell.focus();
                    return true;
                }, [8, 16, 32, 64, 128]);
            }
            return;
        }
        let stop = false;
        const preventDefault = () => {
            stop = true;
        };
        const editData = init ?? structuredClone(row.data);
        props.onEditBegin?.({ api, column, editData, preventDefault, row });
        if (stop)
            return;
        edit.setActiveEdit({ rowId: row.id, column: column.id });
        edit.setEditData(editData);
        api.scrollIntoView({ column, row: rowIndex, behavior: "instant" });
        runWithBackoff(() => {
            const cell = queryCell(gridId, rowIndex, columnIndex, vp);
            if (!cell || cell.getAttribute("data-ln-edit-active") !== "true")
                return false;
            const first = getTabbables(cell, false).at(0);
            if (!first)
                return false;
            first.focus();
            return true;
        }, [8, 16, 32, 64, 128]);
    });
}
